// Parse Telegram Update object
const body = $input.first().json.body || $input.first().json;
const msg = body.message || body.edited_message;
if (!msg) return [{ json: { _skip: true, reason: 'no message' } }];

const chatId = msg.chat.id;
const text = msg.text || msg.caption || '';
const hasUrl = /https?:\/\/[^\s]+/.test(text);
const isVoice = !!msg.voice;
const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const ts = now.toISOString();

// Route: url -> article | text -> brain dump | voice -> future
const route = isVoice ? 'voice' : hasUrl ? 'article' : 'braindump';

return [{ json: { chatId, text, hasUrl, isVoice, route, today, ts, messageId: msg.message_id } }];

const { text, ts } = $input.first().json;

// Append URL to articles-to-process.md
let existing = '';
try {
  const bin = $('S3: Read Articles Queue').first().binary?.data;
  if (bin) existing = Buffer.from(bin.data, 'base64').toString('utf-8');
} catch(e) {}

// Extract all URLs from message
const urls = text.match(/https?:\/\/[^\s]+/g) || [];
const newLines = urls.map(u => `- [ ] ${u} [captured:: ${ts.split('T')[0]}] [source:: telegram]`);

const updated = existing.trimEnd() + '\n' + newLines.join('\n') + '\n';
const buf = Buffer.from(updated, 'utf-8');

return [{ json: {
  ...$input.first().json,
  content: updated,
  key: '00_Inbox/articles-to-process.md',
  urlCount: urls.length,
  replyText: `✅ Queued ${urls.length} article${urls.length!==1?'s':''} for processing.`
}, binary: { data: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: 'articles-to-process.md', fileExtension: 'md', fileSize: buf.length } } }];

// Append text capture to today's brain dump file
const { text, today, ts } = $input.first().json;
const key = `00_Inbox/brain-dumps/BrainDump-Telegram-${today}.md`;

// Brain dump entry with timestamp
const entry = `\n## ${ts.replace('T',' ').substring(0,16)} (Telegram)\n${text}\n`;

// We always append — create file if new, or append if exists (n8n: write full content)
// Strategy: read existing -> append -> write back
const replyText = `✅ Brain dump captured! (${text.length} chars)`;

return [{ json: { ...$input.first().json, key, entry, replyText } }];

const { key, entry, today, replyText } = $('Build Brain Dump Entry').first().json;

// Get existing content (may be empty if new file)
let existing = `---\ndate: ${today}\ntype: brain-dump\nsource: telegram\n---\n\n# Telegram Brain Dump — ${today}\n`;
try {
  const bin = $('S3: Read Existing Dump').first().binary?.data;
  if (bin) existing = Buffer.from(bin.data, 'base64').toString('utf-8');
} catch(e) {}

const updated = existing.trimEnd() + entry;
const buf = Buffer.from(updated, 'utf-8');

return [{ json: {
  ...$('Build Brain Dump Entry').first().json,
  content: updated,
  replyText
}, binary: { data: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: key.split('/').pop(), fileExtension: 'md', fileSize: buf.length } } }];

// Collect reply text from whichever branch ran
let replyText = 'Captured!';
try { replyText = $input.first().json.replyText || replyText; } catch(e) {}
return [{ json: { ...$input.first().json, replyText } }];

// Verify X-Telegram-Bot-Api-Secret-Token header.
// Set TELEGRAM_WEBHOOK_SECRET in n8n environment variables.
// On failure: emit a _skip item rather than throwing — throwing would trigger
// the global error handler and email-spam on every spoofed/malformed request.
const secret = $env.TELEGRAM_WEBHOOK_SECRET || '';
const headers = $input.first().json.headers || {};
const provided = headers['x-telegram-bot-api-secret-token'] || headers['X-Telegram-Bot-Api-Secret-Token'] || '';

if (secret && provided !== secret) {
  return [{ json: { _skip: true, _reason: 'webhook auth failed' } }];
}
return [{ json: { ...$input.first().json, _securityWarning: secret ? null : 'TELEGRAM_WEBHOOK_SECRET not set' } }];
